#include <bits/stdc++.h>
using namespace std;

const int mod=9901;

int a,b,ans=1;

int quick_mi(int x,int y){
    int ans=1,base=x%mod;
    while(y){
        if(y&1)
            ans=ans*base%mod;
        y>>=1,base=base*base%mod;
    }
    return ans;
}

int main(){
    scanf("%d%d",&a,&b);
    for(int i=2;i*i<=a;i++){
        int cnt=0;
        while(a%i==0)
            a/=i,cnt++;
        if(quick_mi(i-1,mod-2)==0)
            ans=ans*(b*cnt+1)%mod;
        else
            ans=ans*(quick_mi(i,b*cnt+1)+mod-1)%mod*quick_mi(i-1,mod-2)%mod;
    }
    if(a>1){
        if(quick_mi(a-1,mod-2)==0)
            ans=ans*(b+1)%mod;
        else
            ans=ans*(quick_mi(a,b+1)+mod-1)%mod*quick_mi(a-1,mod-2)%mod;
    }
    printf("%d\n",ans);
    return 0;
}
